import httpx
from enum import Enum

class ComponentStatus(str, Enum):
    OPERATIONAL = "operational"
    DEGRADED = "degraded_performance"
    PARTIAL_OUTAGE = "partial_outage"
    MAJOR_OUTAGE = "major_outage"
    MAINTENANCE = "under_maintenance"

class IncidentStatus(str, Enum):
    INVESTIGATING = "investigating"
    IDENTIFIED = "identified"
    MONITORING = "monitoring"
    RESOLVED = "resolved"

class StatusPageClient:
    def __init__(self, api_key: str, page_id: str):
        self.client = httpx.Client(
            base_url="https://api.statuspage.io/v1",
            headers={"Authorization": f"OAuth {api_key}"},
        )
        self.page_id = page_id

    def open_incident(
        self,
        name: str,
        body: str,
        component_ids: list[str],
        component_status: ComponentStatus,
    ) -> str:
        resp = self.client.post(
            f"/pages/{self.page_id}/incidents",
            json={
                "incident": {
                    "name": name,
                    "status": IncidentStatus.INVESTIGATING,
                    "body": body,
                    "components": {cid: component_status for cid in component_ids},
                    "deliver_notifications": True,
                }
            }
        )
        resp.raise_for_status()
        return resp.json()["id"]

    def post_update(
        self,
        incident_id: str,
        body: str,
        status: IncidentStatus,
        component_status: ComponentStatus | None = None,
    ) -> None:
        update: dict = {"body": body, "status": status}
        if component_status:
            update["affected_components"] = component_status
        self.client.post(
            f"/pages/{self.page_id}/incidents/{incident_id}/incident_updates",
            json={"incident_update": update},
        ).raise_for_status()

    def resolve(
        self,
        incident_id: str,
        body: str,
        component_ids: list[str],
    ) -> None:
        self.client.patch(
            f"/pages/{self.page_id}/incidents/{incident_id}",
            json={
                "incident": {
                    "status": IncidentStatus.RESOLVED,
                    "body": body,
                    "components": {cid: ComponentStatus.OPERATIONAL for cid in component_ids},
                }
            }
        ).raise_for_status()
